function poblarSelect(
  objeto,
  arreglo,
  valorProp = "id",
  textoProp = "descripcion",
  inicial = "-seleccione-",
  orden = "",
) {
  objeto.innerHTML = "";
  if (inicial != null) {
    objeto.innerHTML = `<option value="">${inicial}</option>`;
  }
  if (!Array.isArray(arreglo)) {
    return;
  }
  if (orden == "") {
    arreglo.sort((a, b) => {
      const textA = a[textoProp].toUpperCase();
      const textB = b[textoProp].toUpperCase();
      return textA < textB ? -1 : textA > textB ? 1 : 0;
    });
  } else {
    arreglo.sort((a, b) => {
      const textA = a[orden];
      const textB = b[orden];
      return textA < textB ? -1 : textA > textB ? 1 : 0;
    });
  }
  arreglo.forEach((item) => {
    const option = document.createElement("option");
    option.value = item[valorProp];
    option.textContent = item[textoProp];
    objeto.appendChild(option);
  });
}
async function retornar_opciones(query, contenedor) {
  try {
    const response = await fetch(`${HOST}/cargar_query`, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        filtros: [configs_token.id_cli],
        id_query: query,
        id_contenedor: contenedor,
      }),
    });
    const opciones = await response.json();
    return opciones;
  } catch (error) {
    console.log(error);
  }
}
//devuelve un objeto con los dtos del query en el BE alojado en el archivo querys.js con multiples filtros
async function retornarQueryFiltrada(query, contenedor, filtro) {
  try {
    const response = await fetch(`${HOST}/cargar_query`, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        filtros: filtro,
        id_query: query,
        id_contenedor: contenedor,
      }),
    });
    const opciones = await response.json();
    return opciones;
  } catch (error) {
    console.log(error);
  }
}

async function getDatosQuery(ruta, metodo = "GET") {
  try {
    const response = await fetch(ruta, {
      method: metodo,
      headers: {
        "Content-Type": "application/json",
        Authorization: `Bearer ${token}`,
      },
    });

    const data = await response.json();

    if (data.error == "El token ha expirado") {
      Swal.fire({
        title: "Error",
        text: "Su sesión ha expirado, por favor inicie sesión nuevamente",
        icon: "error",
        confirmButtonText: "Ok",
      }).then(() => {
        // window.location.href = data.redirectTo + ".html";
      });
      return;
    }
    return data;
  } catch (error) {
    console.error("Error en getDatosQuery:", error);
    return { error: error };
  }
}

