function marcarValid(objeto, valido = true, mensaje = "") {
  if (valido) {
    objeto.classList.add("is-valid");
    setTimeout(() => {
      objeto.classList.remove("is-valid");
    }, 4000);
  } else {
    objeto.classList.add("is-invalid");
    setTimeout(() => {
      objeto.classList.remove("is-invalid");
    }, 4000);
  }
  if (mensaje != "") {
    Swal.fire({
      confirmButtonColor: "#008b8b",
      title: mensaje,
    });
  }
}

async function patchDatos(ruta, elemento, campo, valor) {
  try {
    const response = await fetch(ruta, {
      method: "PATCH",
      headers: {
        "Content-Type": "application/json",
        Authorization: `Bearer ${token}`,
      },
      body: JSON.stringify({ [campo]: valor }),
    });

    const data = await response.json();

    if (data.error) {
      marcarValid(elemento, false, data.error);
      return data.error;
    }

    if (data.success) {
      marcarValid(elemento);
      return data;
    }
  } catch (error) {
    console.log(error);
  }
}
function escapeHtml(str) {
  if (!str) return "";
  return String(str).replace(/[&<>]/g, function (m) {
    if (m === "&") return "&amp;";
    if (m === "<") return "&lt;";
    if (m === ">") return "&gt;";
    return m;
  });
}

function getAge(dateString) {
  var today = new Date();
  var birthDate = new Date(dateString);
  var age = today.getFullYear() - birthDate.getFullYear();
  var m = today.getMonth() - birthDate.getMonth();
  if (m < 0 || (m === 0 && today.getDate() < birthDate.getDate())) {
    age--;
  }
  return age;
}

