function limpiarValor(valor) {
  return valor
    .replace(/[^0-9.]/g, "")
    .replace(/','/g, ".")
    .replace(/(\..*)\./g, "$1");
}

async function crearHeader() {
  if (!document.getElementById("encabezado")) {
    const header = document.createElement("header");
    const div = document.createElement("div");
    div.id = "encabezado";
    header.style.height = "150px";
    header.style.width = "100vw";
    header.appendChild(div);
    document
      .getElementsByTagName("body")[0]
      .insertBefore(
        header,
        document.getElementsByTagName("body")[0].firstChild,
      );
  }
  fetch(`${API_HOST}/api/header/${configs_token.id_cli}`, {
    method: "GET",
    headers: {
      "Content-Type": "application/json",
    },
  })
    .then((response) => response.json())
    .then((result) => {
      document.getElementById("encabezado").innerHTML = result.html;
      const style = document.createElement("style");
      style.id = "estilos-cabecera";
      const cssContent = result.estilos.replace(/<\/?styles?>/gi, "").trim();
      style.textContent = cssContent;
      document.head.appendChild(style);
    });
}

function formatearFecha(fechaISO, tiempo = true) {
  if (!fechaISO) return "Nunca";

  let fecha;
  if (typeof fechaISO === "string" && /^\d{4}-\d{2}-\d{2}$/.test(fechaISO)) {
    const [y, m, d] = fechaISO.split("-").map(Number);
    fecha = new Date(y, m - 1, d);
  } else {
    fecha = new Date(fechaISO);
  }

  if (isNaN(fecha.getTime())) return "Fecha inválida";

  return tiempo
    ? fecha.toLocaleString("es-ES", {
        day: "2-digit",
        month: "2-digit",
        year: "numeric",
        hour: "2-digit",
        minute: "2-digit",
        second: "2-digit",
      })
    : fecha.toLocaleString("es-ES", {
        day: "2-digit",
        month: "2-digit",
        year: "numeric",
      });
}
function formatearMonto(monto) {
  const numero = typeof monto === "string" ? parseFloat(monto) : monto;

  if (isNaN(numero)) {
    return "0,00";
  }

  return new Intl.NumberFormat("es-VE", {
    minimumFractionDigits: 2,
    maximumFractionDigits: 2,
  }).format(numero);
}

