function ajustarHoraUTC4(fechaString) {
  const fecha = new Date(fechaString.replace(" ", "T"));

  const horaUTC = fecha.getUTCHours();
  const minutosUTC = fecha.getUTCMinutes();
  const segundosUTC = fecha.getUTCSeconds();

  let horaLocal = horaUTC - 4;

  if (horaLocal < 0) {
    horaLocal += 24;
  }

  const horaFormateada = horaLocal.toString().padStart(2, "0");
  const minutosFormateados = minutosUTC.toString().padStart(2, "0");
  const segundosFormateados = segundosUTC.toString().padStart(2, "0");

  return `${horaFormateada}:${minutosFormateados}:${segundosFormateados}`;
}

function tabletoExcel(table, name = "SIACmedica") {
  if (typeof table === "string") table = document.getElementById(table);

  // Clonar la tabla para no modificar la original
  const clone = table.cloneNode(true);

  // Template con encoding UTF-8 y estilos básicos para Excel
  const template = `
        <html xmlns:o="urn:schemas-microsoft-com:office:office" 
              xmlns:x="urn:schemas-microsoft-com:office:excel" 
              xmlns="http://www.w3.org/TR/REC-html40">
        <head>
            <meta charset="UTF-8">
            <!--[if gte mso 9]>
            <xml>
                <x:ExcelWorkbook>
                    <x:ExcelWorksheets>
                        <x:ExcelWorksheet>
                            <x:Name>${name}</x:Name>
                            <x:WorksheetOptions>
                                <x:DisplayGridlines/>
                            </x:WorksheetOptions>
                        </x:ExcelWorksheet>
                    </x:ExcelWorksheets>
                </x:ExcelWorkbook>
            </xml>
            <![endif]-->
            <style>
                td { mso-number-format:"\\@"; } /* Forzar texto para preservar formatos */
            </style>
        </head>
        <body>${clone.outerHTML}</body>
        </html>
    `;

  // Crear Blob con encoding UTF-8 + BOM para Excel
  const blob = new Blob(["\ufeff", template], {
    type: "application/vnd.ms-excel;charset=utf-8",
  });
  const link = document.createElement("a");
  link.href = URL.createObjectURL(blob);
  link.download = `${name}.xls`;
  document.body.appendChild(link);
  link.click();
  document.body.removeChild(link);
  URL.revokeObjectURL(link.href);
}
//ajustarFechaHoraUTC4  sumar4 = false (resta 4 horas), sumar4 = true (suma 4 horas), sumar4 = "no" (ni suma ni resta horas)
function ajustarFechaHoraUTC4(fechaString, sumar4 = false) {
  const fecha = new Date(fechaString.replace(" ", "T"));
  switch (sumar4) {
    case false:
      fecha.setTime(fecha.getTime() - 4 * 60 * 60 * 1000);
      break;
    case true:
      fecha.setTime(fecha.getTime() + 4 * 60 * 60 * 1000);
      break;
    case "no":
      fecha.setTime(fecha.getTime());
      break;
    default:
      break;
  }

  const anio = fecha.getFullYear();
  const mes = String(fecha.getMonth() + 1).padStart(2, "0");
  const dia = String(fecha.getDate()).padStart(2, "0");
  const hora = String(fecha.getHours()).padStart(2, "0");
  const minutos = String(fecha.getMinutes()).padStart(2, "0");
  const segundos = String(fecha.getSeconds()).padStart(2, "0");

  let hora24 = fecha.getHours();
  let hora12 = hora24 % 12 || 12;
  let ampm = hora24 >= 12 ? "PM" : "AM";
  const horaMinutosAmpm = `${hora12}:${minutos} ${ampm}`;
  const horaCompletaAmpm = `${hora12}:${minutos}:${segundos} ${ampm}`;

  return {
    fechaCompleta: `${anio}-${mes}-${dia} ${hora}:${minutos}:${segundos}`,
    fechaCompletaFormateada: `${dia}/${mes}/${anio} ${hora}:${minutos}:${segundos}`,
    soloHora: `${hora}:${minutos}:${segundos}`,
    fecha: `${anio}-${mes}-${dia}`,
    soloFechaFormateada: `${dia}/${mes}/${anio}`,
    hora: hora,
    minutos: minutos,
    segundos: segundos,
    horaMinutosAmpm: horaMinutosAmpm,
    horaCompletaAmpm: horaCompletaAmpm,
  };
}

function unfade(element) {
  if (!element) return;
  var op = 0.1;
  var lefty = 25; // initial opacity
  element.style.left = lefty + "%";
  element.style.display = "block";
  var timer = setInterval(function () {
    if (op >= 1) {
      clearInterval(timer);
    }
    element.style.opacity = op;
    element.style.left = lefty + "%";
    element.style.filter = "alpha(opacity=" + op * 100 + ")";
    op += op * 0.1;
    lefty++;
  }, 10);
}

function fade(element) {
  if (!element) return;
  var op = 1; // initial opacity
  var lefty = 50; // initial opacity
  var timer = setInterval(function () {
    if (op <= 0.1) {
      clearInterval(timer);
      element.style.display = "none";
    }
    element.style.opacity = op;
    element.style.left = lefty + "%";
    element.style.filter = "alpha(opacity=" + op * 100 + ")";
    op -= op * 0.1;
    lefty--;
  }, 10);
}

function corregirTexto(texto) {
  const encoder = new TextEncoder();
  const decoder = new TextDecoder("utf-8");
  const bytes = new Uint8Array([...texto].map((c) => c.charCodeAt(0)));
  return decoder.decode(bytes);
}
