async function enviarPseudoplantilla(
  nombrePlantilla,
  destino,
  variables = {},
  paciente,
  elemento,
  masivo = false,
  idioma = "es",
) {
  const payload = masivo
    ? {
        empresa_id: configs_token.id_cli,
        destinos: destino,
        plantilla: nombrePlantilla,
        usar_pseudoplantilla: true,
        idioma: idioma,
        datos: variables,
        id_paciente: paciente,
      }
    : {
        empresa_id: configs_token.id_cli,
        destino: destino,
        plantilla: nombrePlantilla,
        usar_pseudoplantilla: true,
        idioma: idioma,
        datos: variables,
        id_paciente: paciente,
      };

  const respuesta = await postDatos(
    `${API_HOST}/api/whatsapp/enviar-plantilla${masivo ? "-masiva" : ""}`,
    payload,
    elemento,
    "POST",
  );

  return respuesta;
}

